// Combine the agent's decision with the original task
const content = $json.content || [];
const tb = content.find(c => c.type === 'text') || content[0] || {};
const txt = tb.text || '';
const priority = Number((txt.match(/PRIORITY:\s*(\d)/i) || [])[1] || 3);
const confidence = Number((txt.match(/CONFIDENCE:\s*([\d.]+)/i) || [])[1] || 0);
const reason = ((txt.match(/REASON:\s*(.+)/i) || [])[1] || '').trim();
const task = $('Parse tasks').item.json;
return { json: { ...task, priority, confidence, reason } };

